patch:
--- a/adder.v
+++ b/adder.v
@@ -1,10 +1,10 @@
 module Adder4bit (
   input [3:0] a,
   input [3:0] b,
   output [4:0] sum
 );
   assign sum = a + b;
 endmodule

 module top;
-  Adder4bit adder_inst (.input_a(4'b1010), .input_b(4'b0101), .output_sum(result));
+  Adder4bit adder_inst (.a(4'b1010), .b(4'b0101), .sum(result));
 endmodule

before_code:
module Adder4bit (
  input [3:0] a,
  input [3:0] b,
  output [4:0] sum
);
  assign sum = a + b;
endmodule

module top;
  wire [4:0] result;
  Adder4bit adder_inst (.input_a(4'b1010), .input_b(4'b0101), .output_sum(result));
endmodule

after_code:
module Adder4bit (
  input [3:0] a,
  input [3:0] b,
  output [4:0] sum
);
  assign sum = a + b;
endmodule

module top;
  wire [4:0] result;
  Adder4bit adder_inst (.a(4'b1010), .b(4'b0101), .sum(result));
endmodule
